const BASE_URL = '/api/products';

async function request(url, options = {}) {
  console.log(`→ ${options.method || 'GET'} ${url}`);

  try {
    const response = await fetch(url, {
      ...options,
      headers: {
        'Content-Type': 'application/json',
        ...options.headers,
      },
    });

    console.log(`← ${response.status} ${url}`);

    if (!response.ok) {
      let errorText = 'Нет описания ошибки';
      try {
        errorText = await response.text();
      } catch {}
      throw new Error(`${response.status} — ${errorText}`);
    }

    if (response.status === 204) {
      return null; // DELETE обычно возвращает 204 без тела
    }

    return response.json();
  } catch (err) {
    console.error('Ошибка fetch:', err.message);
    throw err;
  }
}

export async function getProducts() {
  return request(BASE_URL);
}

export async function createProduct(data) {
  return request(BASE_URL, {
    method: 'POST',
    body: JSON.stringify(data),
  });
}

export async function updateProduct(id, data) {
  return request(`${BASE_URL}/${id}`, {
    method: 'PATCH',
    body: JSON.stringify(data),
  });
}

export const deleteProduct = async (id) => {
  console.log(`[DELETE] Запрос на удаление ID: ${id}`);

  const response = await fetch(`/api/products/${id}`, {
    method: 'DELETE',
  });

  console.log(`[DELETE] Получен статус: ${response.status}`);

  // 204 — это успех для DELETE (нет тела ответа)
  if (response.status === 204) {
    console.log('[DELETE] Успешно удалено (204)');
    return true;
  }

  // Если не 204 и не 200–299 → ошибка
  if (!response.ok) {
    let errorMsg = 'Неизвестная ошибка';
    try {
      errorMsg = await response.text();
    } catch {}
    console.error('[DELETE] Ошибка сервера:', response.status, errorMsg);
    throw new Error(`Удаление не удалось: ${response.status} — ${errorMsg}`);
  }

  return true;
};
